import android.app.Service
import android.content.Context
import android.content.Intent
import android.os.IBinder
import android.util.Log
import androidx.core.app.JobIntentService
import java.security.SecureRandom

class BackgroundTaskService : JobIntentService() {
    companion object {
        private const val TAG = "BackgroundTaskService"
        private const val ACTION_SYNC = "com.yourapp.action.SYNC"
        private const val ACTION_CLEANUP = "com.yourapp.action.CLEANUP"
        private const val EXTRA_TASK_ID = "task_id"
        private const val EXTRA_PARAMETERS = "parameters"
        private const val EXTRA_AUTH_TOKEN = "auth_token"
        private const val JOB_ID = 1001
        
        fun enqueueWork(context: Context, intent: Intent) {
            enqueueWork(context, BackgroundTaskService::class.java, JOB_ID, intent)
        }
    }
    
    override fun onHandleWork(intent: Intent) {
        try {
            val action = intent.action
            val authToken = intent.getStringExtra(EXTRA_AUTH_TOKEN)
            
            if (!validateAuthToken(authToken)) {
                Log.e(TAG, "Invalid authentication token")
                return
            }
            
            when (action) {
                ACTION_SYNC -> handleSyncTask(intent)
                ACTION_CLEANUP -> handleCleanupTask(intent)
                else -> Log.w(TAG, "Unknown action: $action")
            }
        } catch (e: Exception) {
            Log.e(TAG, "Error processing background task", e)
        }
    }
    
    private fun handleSyncTask(intent: Intent) {
        val taskId = intent.getStringExtra(EXTRA_TASK_ID)
        val parameters = intent.getSerializableExtra(EXTRA_PARAMETERS) as? Map<String, Any>
        
        Log.d(TAG, "Starting sync task: $taskId")
        
        try {
            // Simulate data synchronization
            Thread.sleep(2000)
            
            // Process parameters securely
            parameters?.let { params ->
                val syncType = params["type"] as? String
                val syncData = params["data"] as? String
                Log.d(TAG, "Sync type: $syncType, data length: ${syncData?.length}")
            }
            
            Log.d(TAG, "Sync task completed: $taskId")
        } catch (e: Exception) {
            Log.e(TAG, "Sync task failed: $taskId", e)
        }
    }
    
    private fun handleCleanupTask(intent: Intent) {
        val taskId = intent.getStringExtra(EXTRA_TASK_ID)
        val parameters = intent.getSerializableExtra(EXTRA_PARAMETERS) as? Map<String, Any>
        
        Log.d(TAG, "Starting cleanup task: $taskId")
        
        try {
            // Simulate cleanup operations
            Thread.sleep(1500)
            
            // Process cleanup parameters
            parameters?.let { params ->
                val cleanupType = params["type"] as? String
                val retentionDays = params["retention_days"] as? Int
                Log.d(TAG, "Cleanup type: $cleanupType, retention: $retentionDays days")
            }
            
            Log.d(TAG, "Cleanup task completed: $taskId")
        } catch (e: Exception) {
            Log.e(TAG, "Cleanup task failed: $taskId", e)
        }
    }
    
    private fun validateAuthToken(token: String?): Boolean {
        if (token.isNullOrEmpty()) return false
        
        // Secure token validation - in real app, this would be more complex
        val validToken = generateSecureToken()
        return token == validToken
    }
    
    private fun generateSecureToken(): String {
        val random = SecureRandom()
        val bytes = ByteArray(32)
        random.nextBytes(bytes)
        return bytes.joinToString("") { "%02x".format(it) }
    }
    
    override fun onBind(intent: Intent): IBinder? = null
}